import{_ as i,o as t,c as s,a2 as a}from"./chunks/framework.DBPoZGF_.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{"layout":"home","hero":{"name":"appstore-flow","text":"App Store Connect from your terminal","tagline":"Manage iOS listings, IAPs, subscriptions, and screenshots from YAML files. CLI + bundled MCP server.","actions":[{"theme":"brand","text":"Get started","link":"/getting-started"},{"theme":"alt","text":"View on GitHub","link":"https://github.com/zmij/appstore-cli"}]},"features":[{"icon":"📝","title":"YAML-first","details":"Pull every per-locale listing, IAP catalogue, subscription, and screenshot summary into committed YAML. Edit in your editor; sync back."},{"icon":"🔄","title":"Two-way reconcile","details":"Field-level diff with paths like `subscriptions/my_sub/intro_offers/.../start_date`. Pull updates without clobbering local edits."},{"icon":"🤖","title":"Bundled MCP server","details":"Same client code, exposed over stdio. Any MCP-aware agent (Claude Code, Cursor, Cline, Windsurf) can read and update live store state."},{"icon":"💰","title":"Price + subscriber migrations","details":"Migrate existing subscribers when a price changes via Apple\'s `batchMigratePrices`. Dry-run by default; `--confirm` to fire."},{"icon":"⚡","title":"One install, two binaries","details":"Single `npm install`, two binaries (`appstore` + `appstore-mcp`). Configurable for any iOS project via env vars or `appstore-cli.config.yaml` (legacy config-file name from before the npm rebrand)."},{"icon":"🌍","title":"Locale-aware","details":"Built and battle-tested on Lazy Sudoku\'s 14-locale listing and 173-territory pricing matrix."}]},"headers":[],"relativePath":"index.md","filePath":"index.md","lastUpdated":1782052837000}'),n={name:"index.md"};function r(o,e,l,p,d,h){return t(),s("div",null,[...e[0]||(e[0]=[a('<h2 id="what-it-does" tabindex="-1">What it does <a class="header-anchor" href="#what-it-does" aria-label="Permalink to &quot;What it does&quot;">​</a></h2><p><code>appstore-flow</code> puts your iOS store presence under version control. Instead of clicking through App Store Connect&#39;s per-locale tabs to update copy, prices, or screenshots, you pull live state into committed YAML, edit it in your editor, and sync it back through normal PR review.</p><p>The bundled <code>appstore-mcp</code> server exposes the same client code over stdio so any MCP-aware agent — Claude Code, Cursor, Windsurf, Cline, Continue, Zed — can read and update live store state without shelling out.</p><h2 id="quick-install" tabindex="-1">Quick install <a class="header-anchor" href="#quick-install" aria-label="Permalink to &quot;Quick install&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> appstore-flow</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># or, from a checkout (the GitHub repo is still `appstore-cli` —</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># only the npm package name has been rebranded to `appstore-flow`):</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/zmij/appstore-cli.git</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> appstore-cli</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> link</span></span></code></pre></div><p>Then see <a href="/appstore-cli/getting-started">Get started</a> for the first-run walkthrough.</p><h2 id="in-production" tabindex="-1">In production <a class="header-anchor" href="#in-production" aria-label="Permalink to &quot;In production&quot;">​</a></h2><blockquote><p>I built this to manage <a href="https://lazy-sudoku.online" target="_blank" rel="noreferrer">Lazy Sudoku</a>&#39;s App Store listing — 14 locales, 12 IAP products across 173 territories of pricing, plus subscription groups with intro offers. Editing YAML in my editor and running <code>appstore listings sync</code> / <code>appstore iap sync</code> is dramatically less error-prone than clicking through App Store Connect&#39;s per-locale tabs, and lets every store change land via normal PR review.</p><p>— <em>Sergei Fedorov, <a href="https://lazy-sudoku.online" target="_blank" rel="noreferrer">Lazy Sudoku</a></em></p></blockquote><p>Using appstore-flow somewhere? <a href="https://github.com/zmij/appstore-cli/blob/master/README.md" target="_blank" rel="noreferrer">Open a PR</a> adding yourself to the Adopters section in the README.</p>',9)])])}const k=i(n,[["render",r]]);export{u as __pageData,k as default};
